package com.cho2hand.marketplace.controller.comment;import com.cho2hand.marketplace.dto.comment.*;import com.cho2hand.marketplace.service.comment.CommentService;import jakarta.validation.Valid;import jakarta.validation.constraints.Positive;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/v1/listings/{listingId}/comments")public class CommentController{private final CommentService service;public CommentController(CommentService s){service=s;}@GetMapping public List<CommentResponse> list(@PathVariable@Positive Long listingId){return service.list(listingId);}@PostMapping@ResponseStatus(HttpStatus.CREATED)public CommentResponse create(@AuthenticationPrincipal Long user,@PathVariable@Positive Long listingId,@Valid@RequestBody CreateCommentRequest request){return service.create(user,listingId,request);}}
